use utils::{is_safe_command, load_history, save_history};

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let _ = dotenv();
    let args = Args::parse();
    let config = utils::load_config();

    if let Some(dirs) = &config.init_directories {
        for dir in dirs {
